}

% Uso
\begin{teorema_box}{3.1 (Teorema de Bayes)}
Para eventos $A$ y $B$ con $P(B) &gt; 0$:
\[
    P(A|B) = \frac{P(B|A) \cdot P(A)}{P(B)}
\]
\end{teorema_box}

